#include <cstdio>
#include <iostream>
#include <iomanip>
#include <cmath>
#include <limits>
#include <ctime>
#include <chrono>

#define N 2048
#define IDX(i, j) ((i) + (j) * N)

void initialize_data(float* f) {
    for (int j = 0; j < N; ++j) {
        for (int i = 0; i < N; ++i) {
            if (i == 0 || N-1 == i) {
                f[IDX(i,j)] = sinf(j * 2 * M_PI / (N - 1));
            }
            else if (0 == j || N-1 == j) {
                f[IDX(i,j)] = sinf(i * 2 * M_PI / (N - 1));
            }
            else {
                f[IDX(i,j)] = 0.0f;
            }
        }
    }
}

__global__ void compute_step(float* f, float* f_old, float* error_ptr, int N) {
    float local_error = 0.0f;

    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    int total_threads = blockDim.x * gridDim.x;

    int interior_size = (N-2) * (N-2);

    for (int idx = tid; idx < interior_size; idx += total_threads) {
        int i = idx % (N-2) + 1;
        int j = idx / (N-2) + 1;

        float t = 0.25f * (f_old[IDX(i-1,j)] +
                           f_old[IDX(i+1,j)] +
                           f_old[IDX(i,j-1)] +
                           f_old[IDX(i,j+1)]);
        float df = t - f_old[IDX(i, j)];
        f[IDX(i,j)] = t;
        local_error += df * df;
    }

    atomicAdd(error_ptr, local_error);
}

__global__ void copy_f_to_f_old(float* f, float* f_old, int N) {
    int tid = blockIdx.x * blockDim.x + threadIdx.x;
    int total_threads = blockDim.x * gridDim.x;

    int interior_size = (N-2) * (N-2);

    for (int idx = tid; idx < interior_size; idx += total_threads) {
        int i = idx % (N-2) + 1;
        int j = idx / (N-2) + 1;
        f_old[IDX(i,j)] = f[IDX(i,j)];
    }
}

int main() {
    auto start_time = std::chrono::steady_clock::now();

    float* f_host = (float*)malloc(N * N * sizeof(float));
    float* f_old_host = (float*)malloc(N * N * sizeof(float));

    float* f;
    float* f_old;
    cudaMalloc(&f, N * N * sizeof(float));
    cudaMalloc(&f_old, N * N * sizeof(float));

    float error = std::numeric_limits<float>::max();
    const float tolerance = 1.e-5f;

    initialize_data(f_host);
    initialize_data(f_old_host);

    cudaMemcpy(f, f_host, N * N * sizeof(float), cudaMemcpyHostToDevice);
    cudaMemcpy(f_old, f_old_host, N * N * sizeof(float), cudaMemcpyHostToDevice);

    const int max_iters = 10000;
    int num_iters = 0;

    auto start = std::chrono::steady_clock::now();

    float* error_ptr;
    cudaMalloc(&error_ptr, sizeof(float));

    int num_teams = N * N / 256;
    int thread_limit = 256;

    while (tolerance < error && num_iters < max_iters) {
        error = 0.f;
        cudaMemcpy(error_ptr, &error, sizeof(float), cudaMemcpyHostToDevice);

        compute_step<<<num_teams, thread_limit>>>(f, f_old, error_ptr, N);

        float temp_error;
        cudaMemcpy(&temp_error, error_ptr, sizeof(float), cudaMemcpyDeviceToHost);
        error = sqrtf(temp_error / (N * N));

        copy_f_to_f_old<<<num_teams, thread_limit>>>(f, f_old, N);

        if (num_iters % 1000 == 0) {
            std::cout << "Error after iteration " << num_iters << " = " << error << std::endl;
        }

        ++num_iters;
    }

    auto end = std::chrono::steady_clock::now();
    auto time = std::chrono::duration_cast<std::chrono::nanoseconds>(end - start).count();
    std::cout << "Average execution time per iteration: " << (time * 1e-9f) / num_iters << " (s)\n";

    if (tolerance >= error && max_iters > num_iters) {
        std::cout << "PASS" << std::endl;
    }
    else {
        std::cout << "FAIL" << std::endl;
        cudaFree(f);
        cudaFree(f_old);
        cudaFree(error_ptr);
        free(f_host);
        free(f_old_host);
        return -1;
    }

    cudaFree(f);
    cudaFree(f_old);
    cudaFree(error_ptr);
    free(f_host);
    free(f_old_host);

    auto end_time = std::chrono::steady_clock::now();
    auto total_time = std::chrono::duration_cast<std::chrono::nanoseconds>(end_time - start_time).count();
    double duration = total_time * 1e-9;
    std::cout << "Total elapsed time: " << std::setprecision(4) << duration << " seconds" << std::endl;

    return 0;
}
